import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, LogOut } from 'lucide-react';

const Header = ({ isLoggedIn, cerrarSesion }) => {
  const navigate = useNavigate();

  return (
    <header style={headerContainer}>
      {/* Lado Izquierdo: LOGO */}
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span>
        <span style={logoOrange}>APP</span>
      </div>

      {/* Lado Derecho: ACCIONES */}
      <nav style={navLinks}>
        {!isLoggedIn ? (
          <>
            <Link to="/register" style={registerLink}>
              <User size={18} />
              <span>Crear una cuenta</span>
            </Link>
            <Link to="/login" style={loginButton}>
              Ingresar
            </Link>
          </>
        ) : (
          <>
            <Link to="/dashboard" style={registerLink}>Mi Panel</Link>
            <button onClick={cerrarSesion} style={logoutBtn}>
              <LogOut size={18} />
              <span>Salir</span>
            </button>
          </>
        )}
      </nav>
    </header>
  );
};

/* --- ESTILOS INSPIRADOS EN TU IMAGEN --- */
const headerContainer = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '0 5%',
  background: '#1e293b', // Azul muy oscuro/grisáceo como el de la foto
  height: '75px',
  boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
  position: 'sticky',
  top: 0,
  zIndex: 1000
};

const logoSection = { 
  cursor: 'pointer', 
  fontSize: '1.6rem', 
  fontWeight: '800', 
  letterSpacing: '0.5px' 
};

const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '5px' };

const navLinks = { 
  display: 'flex', 
  alignItems: 'center', 
  gap: '20px' 
};

const registerLink = { 
  color: '#ffffff', 
  textDecoration: 'none', 
  fontSize: '0.95rem', 
  display: 'flex', 
  alignItems: 'center', 
  gap: '8px',
  fontWeight: '500'
};

const loginButton = {
  background: '#e67e22', // Naranja vibrante de la imagen
  color: 'white',
  padding: '10px 25px',
  borderRadius: '12px',
  textDecoration: 'none',
  fontWeight: 'bold',
  fontSize: '0.95rem',
  transition: '0.3s'
};

const logoutBtn = {
  background: 'transparent',
  color: '#ffffff',
  border: '1px solid #e67e22',
  padding: '8px 15px',
  borderRadius: '12px',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  fontWeight: '500'
};

export default Header;
